parameters.jsCode:
const rdv = items[0].json[0];
if (!rdv || !rdv.clients || !rdv.clients.email) {
  return [{ json: { skip: true, reason: 'Pas de client ou pas d email' } }];
}

const client = rdv.clients;
const profile = rdv.profiles || {};
const startDate = new Date(rdv.start_time);
const dateStr = startDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
const timeStr = startDate.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

return [{
  json: {
    skip: false,
    client_email: client.email,
    client_name: `${client.first_name} ${client.last_name}`,
    client_first_name: client.first_name,
    user_id: rdv.user_id,
    client_id: rdv.client_id,
    rdv_title: rdv.title,
    rdv_description: rdv.description || '',
    rdv_date: dateStr,
    rdv_time: timeStr,
    rdv_location: rdv.location || 'A confirmer',
    rdv_type: rdv.type,
    agent_name: profile.full_name || 'Alison Mendes',
    agent_business: profile.business_name || 'Visit & Smile',
    agent_phone: profile.phone || ''
  }
}];

